var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"휴, 아슬아슬했어.","JPN":"ふう、危なかったぜ。","ENG":"Phew, that was close.","TWN":"呼，好險。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"조용하군. 쫓아오진 않는 것 같다.","JPN":"静かになったな。追いかけては来ないみたいだ。","ENG":"Quiet. It doesn't seem to be following us.","TWN":"安靜一點。它看起來並不是在追我們。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"후아- 이렇게 심장이 뛰어본 적은 간만이네요.","JPN":"ふぁ～久しぶりに心臓がバクバクしました。","ENG":"Huah! I've never had my heart race this fast in a while.","TWN":"呼——心臟好久沒有跳得這麼快了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"방금 그건 뭐였을까요?","JPN":"あの怪物は何だったと思いますか？","ENG":"What was that?","TWN":"剛才那個到底是什麼東西？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"4종 침식체 이터…","JPN":"第4種侵食体イーター……","ENG":"A Category 4 C.O. Eater...","TWN":"4類侵蝕體——暴食……"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"특수한 감각 기관으로 먼 곳에서도 카운터가 쓰는 CRF를 감지하고 추적해오는 개체지.","JPN":"特殊な感覚器官を持ち、遠くからでもカウンターが使うCRFを感知して追ってくる個体だ。","ENG":"It's an entity with a special sensory organ that can detect CRF used by Counters from afar.","TWN":"它可以利用特殊的感覺器官，從遠處感知和跟蹤制裁者使用的CRF。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐? 그럼 힉스가 능력을 써서 여기까지 나타난 거라고?","JPN":"なんだって？　じゃあヒックスが能力を使ったせいで嗅ぎつけられたってことか？","ENG":"What? Then it showed up because Hicks used her powers?","TWN":"什麼？那麼，是因為希克斯使用了制裁者能力，它才出現在這裡的嗎？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그런 건가요?!","JPN":"そ、そうなんですか！？","ENG":"Is that why?!","TWN":"是、是這樣嗎？！"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"죄송해요, 스펜서! 제가 팀 전체를 위험에 빠트릴 줄은 몰랐어요!","JPN":"本当にすみません、スペンサーさん！　私のせいでチームのみなさんを危険な目に遭わせてしまいました。","ENG":"I'm sorry, Spencer! I didn't think I'd put the whole team at risk!","TWN":"對不起，史賓瑟！我不知道是我的原因，才讓大家陷入了危險！"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"진정해. 네가 아니었으면 우린 이터가 아니라 1종들의 밥이 됐을 테니까.","JPN":"気にするな。あなたがいなかったら、私たちはイーターどころか、第1種にもやられてしまっていたさ。","ENG":"Calm down. If it weren't for you, we would've been dinner for those Category 1s.","TWN":"冷靜點。如果沒有你，我們就會成為剛剛那些1類侵蝕體的食物。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당분간 놈도 이 시설을 떠나지 않을 테니, 앞으로 주의하면 돼.","JPN":"あの化け物はしばらくこの施設を徘徊するはずだ。気をつけて進もう。","ENG":"That thing won't be leaving this facility for a while, so just watch out.","TWN":"看起來它暫時不會離開這個設施了，我們以後要小心一點。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"벌은… 안 받아도 되는 건가요?","JPN":"罰とかは……ないんですか？","ENG":"I... don't have to be punished?","TWN":"不用……懲罰我嗎？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"자 자, 다 같이 무사하니 된 거지 뭐.","JPN":"まぁまぁ、全員無事なんだし、結果オーライってことだろう。","ENG":"Now, now. We're all safe and sound, so it's all good.","TWN":"好了好了，大家平安無事就行。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"대장도 살아있어서 다행이야.","JPN":"隊長も生きていてよかったぜ。","ENG":"Good thing Captain's alive too.","TWN":"我很高興隊長也還活著。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"낭떠러지로 떨어졌을 땐 영락없이 죽은 줄 알았다고.","JPN":"あの溝に落下しちまったときは、間違いなく死んだと思ったぜ。","ENG":"I thought you were dead for sure when you fell off that cliff.","TWN":"當你掉下去的時候，我們還以為你已經死了呢。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"걱정을 끼쳤네.","JPN":"心配をかけてしまったな。","ENG":"Sorry for the trouble.","TWN":"讓你擔心了。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체들에겐 어쩌다 쫓기던 거야?","JPN":"ところで、どういった経緯で侵食体に追いかけられていた？","ENG":"How did you run into those C.O.s?","TWN":"你們呢？為什麼會被侵蝕體追著？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"의료동으로 이동하던 중에 놈들과 마주쳤다.","JPN":"医療棟に向かう途中で、奴らと出くわした。","ENG":"We ran into them while heading to the medical wing.","TWN":"我們在前往醫療大樓的途中遇到了它們。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이터니움이 있는 곳이라 그런지 침식체가 즐비하더군.","JPN":"エタニウムがありそうな場所だったが、そのせいか奴らが密集してやがった。","ENG":"The place was crawling with C.O.s. Must be because of all the Eternium there.","TWN":"那裡到處都是密密麻麻的侵蝕體，估計是因為有永恆之金。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체를 마주쳤다면, 거기엔 침입자가 있을 가능성이 낮아.","JPN":"侵食体がいたってことは、侵入者がそこにいる可能性は低いな。","ENG":"If you encountered C.O.s there, it's unlikely the intruder's there.","TWN":"嗯，那個地方都是侵蝕體的話，入侵者不太可能會去那裡。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다른 곳을 먼저 찾아보는 게 좋겠네.","JPN":"そこは候補から一旦外して進むか。","ENG":"Best we explore elsewhere first.","TWN":"我們最好先看看其他地方。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"저기. 그런데 말이지.","JPN":"あ、あと、もう一つあるんだが。","ENG":"Hey, also...","TWN":"那個，我說啊……"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"승강기가 망가졌어. 다른 돌아갈 방법을 먼저 찾아 두는 편이 좋을 것 같아.","JPN":"昇降機が壊れて使用不可になった。帰還できる手段を探しておくべきだろう。","ENG":"The elevator's out of order. We should secure another way back first.","TWN":"升降機……壞了。我覺得還是先想辦法回去比較好。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"베이스포인트엔 왜곡 필터가 작동하고 있었을 텐데. 침식체가 거길 발견했단 거야?","JPN":"ベース拠点では歪曲フィルターが作動中のはずなのに、侵食体に狙われたというのか？","ENG":"A distortion filter should be running at the basepoint. But the C.O.s found it anyway?","TWN":"基點的扭曲濾鏡應該還在運行。侵蝕體怎麼還會去那裡？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"으음… 그게 말이지…? 침식체가 아니라 지알로 녀석이 컨트롤 패널을 쏴 버렸거든.","JPN":"うーん……それがな？　実は、侵食体じゃなくて、ジャッロのやつがコントロールパネルを銃で撃ちやがったんだ。","ENG":"Umm... The thing is... It wasn't the C.O.s. Giallo shot the control panel.","TWN":"呃……那個……不是侵蝕體，是賈洛那傢伙，他開槍打壞了控制台。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"죽은 대원이… 승강기 패널을 쐈다고?","JPN":"死んだ隊員が、昇降機のパネルを撃っただと？","ENG":"A dead man... shot the panel?","TWN":"已經死了的賈洛……開槍打壞了升降機的控制台？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래, 시체가 우리 생명줄을 끊어 버리다니. 말도 안 되는 소리지.","JPN":"ああ、死体が俺たちの生命線を断ち切っちまったとは、到底信じられねえだろうが。","ENG":"Yeah. A corpse cut our lifeline. Ridiculous.","TWN":"沒錯，居然被一具屍體斷了生路。你說荒唐不荒唐。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};